<script lang="ts">
  import { tabsCloseClassName, tabsItemClassName } from '@fex/components-styles/tabs'; import { cn } from '@fex/utils'; import { getContext, type Snippet } from 'svelte'; import type { HTMLAttributes, HTMLButtonAttributes } from 'svelte/elements'; import { tabsContextKey, type TabsContextValue } from './context'
  import CloseIcon from '../../icon/close.svelte'
  interface Props extends Omit<HTMLAttributes<HTMLDivElement>, 'children'> { value: string, disabled?: boolean | undefined, closable?: boolean | undefined, children?: Snippet, render?: Snippet<[{ props: HTMLAttributes<HTMLElement>, state: ReturnType<TabsContextValue['itemState']>, closeProps: HTMLButtonAttributes, itemRef: (node: HTMLElement) => { destroy: () => void } }]> }
  let { value, disabled = false, closable = false, children, render, class: className, ...rest }: Props = $props(); const tabs = getContext<TabsContextValue>(tabsContextKey); if (!tabs) throw new Error('TabsItem must be used inside TabsRoot.'); const { snapshot } = tabs; const item = $derived({ value, disabled, closable }); const state = $derived.by(() => { $snapshot; return tabs.itemState(item) }); const renderProps = $derived.by(() => { $snapshot; return { ...rest, ...tabs.getItemProps(item), class: cn(tabsItemClassName({ variant: tabs.variant() }), className) } }); const closeProps = $derived({ ...tabs.getCloseProps(item), class: tabsCloseClassName }); function itemRef(node: HTMLElement) { tabs.registerItem(item, node); return { destroy: () => tabs.registerItem(item, null) } }
</script>
{#if render}{@render render({ props: renderProps, state, closeProps, itemRef })}{:else}<div {...renderProps} use:itemRef>{@render children?.()}{#if closable}<button {...closeProps}><CloseIcon class="size-4" /></button>{/if}</div>{/if}
